        final Integer integer = createInteger(str);
        // If successful, check if it's negative (meaning it overflowed into the negative range)
        // A positive hex number that appears negative has overflowed Integer range
        if (integer >= 0 || hexDigits <= 8) { // If positive or has 8 or fewer digits, it fits in Integer
            return integer;
