        // If we can't create an Integer, it might be out of range
        // Continue to try as Long or BigInteger
    }
    // If the hex number has 8 or fewer digits but still caused overflow (e.g., 0x80000000)
    // or has 9-16 digits, then try as Long
    if (hexDigits > 8) {
        return createLong(str);
    }
    // For 8 or fewer digits that overflow Integer, try as Long
    try {
        return createLong(str);
    } catch (final NumberFormatException nfe) {
        // If it doesn't fit in Long either, use BigInteger
        return createBigInteger(str);
    }
}

